local _K="ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"
local function _D(d)
  local r,p="",1
  local function v(c)
    if c=="=" then return 0 end
    local n=_K:find(c,1,true)
    return n and n-1 or 0
  end
  while p<=#d do
    local a,b,c,e=v(d:sub(p,p)),v(d:sub(p+1,p+1)),v(d:sub(p+2,p+2)),v(d:sub(p+3,p+3))
    r=r..string.char((a<<2)|(b>>4))
    if d:sub(p+2,p+2)~="=" then r=r..string.char(((b&15)<<4)|(c>>2)) end
    if d:sub(p+3,p+3)~="=" then r=r..string.char(((c&3)<<6)|e) end
    p=p+4
  end
  return r
end
local _src=_D("")
